{"code": "import json

# Test the approach with a smaller subset to understand the data structure
uc_data = locals()['var_functions.query_db:16']
if isinstance(uc_data, str):
    with open(uc_data, 'r') as f:
        uc_data = json.load(f)

# Extract UC publication numbers and their CPC codes
uc_pubs = []
for row in uc_data:
    patents_info = row.get('Patents_info', '')
    cpc_json = row.get('cpc', '[]')

    # Try to find US publication numbers
    import re
    pub_match = re.search(r'(?:pub\.? number|publication number|publication no\.?)\s+([A-Z0-9-]+)', patents_info, re.IGNORECASE)
    if pub_match:
        pub_num = pub_match.group(1)
        if 'US-' in pub_num:
            uc_pubs.append({
                'pub_num': pub_num,
                'patents_info': patents_info,
                'cpc': cpc_json
            })

print('__RESULT__:')
print(json.dumps({
    'uc_patents_found': len(uc_pubs),
    'sample_uc_pubs': uc_pubs[:3]
}, indent=2))"}

