function.arguments:
{"code": "import json
import re

# Load UNIV CALIFORNIA patents
uc_data = locals()['var_functions.query_db:30']
if isinstance(uc_data, str):
    with open(uc_data, 'r') as f:
        uc_data = json.load(f)

# Extract UC publication numbers
uc_pub_numbers = set()
for row in uc_data:
    patents_info = row.get('Patents_info', '')

    # Extract publication number (various formats)
    patterns = [
        r'pub\.? number\s+([A-Z0-9-]+)',
        r'publication number\s+([A-Z0-9-]+)',
        r'publication no\.?\s+([A-Z0-9-]+)',
        r'([A-Z]{2}-[0-9]+-[A-Z][0-9]?)'  # US-XXXXX-X format
    ]

    for pattern in patterns:
        matches = re.findall(pattern, patents_info, re.IGNORECASE)
        for match in matches:
            if 'US-' in match or 'WO-' in match or 'EP-' in match:
                uc_pub_numbers.add(match.strip())

print('__RESULT__:')
print(json.dumps({
    'uc_patents_found': len(uc_data),
    'uc_pub_numbers_extracted': len(uc_pub_numbers),
    'sample_uc_pub_numbers': list(uc_pub_numbers)[:10]
}, indent=2))"}

